## Testing your implementation

These examples demonstrate how to test your implementation when using Calendar within your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Rendering Tests

Verify the Calendar component renders with expected grid structure

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen, within, act } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Calendar, NimbusProvider } from "@commercetools/nimbus";
import { CalendarDate, getLocalTimeZone } from "@internationalized/date";

describe("Calendar - Basic rendering", () => {
  it("renders calendar grid", () => {
    render(
      <NimbusProvider>
        <Calendar aria-label="Select date" />
      </NimbusProvider>
    );

    // Calendar uses grid role for accessibility
    expect(screen.getByRole("grid")).toBeInTheDocument();
  });

  it("renders with default value", () => {
    const defaultDate = new CalendarDate(2025, 1, 15);

    render(
      <NimbusProvider>
        <Calendar aria-label="Select date" defaultValue={defaultDate} />
      </NimbusProvider>
    );

    const grid = screen.getByRole("grid");
    expect(grid).toBeInTheDocument();

    // Verify selected date is marked with data-selected attribute
    const dateCells = within(grid).getAllByRole("button");
    const selectedCell = dateCells.find(
      (cell) => cell.getAttribute("data-selected") === "true"
    );
    // Calendar renders with a selected date
    expect(selectedCell).toBeTruthy();
    if (selectedCell) {
      expect(selectedCell).toHaveTextContent("15");
    }
  });

  it("renders navigation buttons", () => {
    render(
      <NimbusProvider>
        <Calendar aria-label="Select date" />
      </NimbusProvider>
    );

    // Calendar header contains previous/next month and year navigation
    const previousButtons = screen.getAllByRole("button", {
      name: /previous/i,
    });
    const nextButtons = screen.getAllByRole("button", { name: /next/i });

    expect(previousButtons.length).toBeGreaterThan(0);
    expect(nextButtons.length).toBeGreaterThan(0);
  });
});
```

### Controlled Mode Tests

Test controlled Calendar with value and onChange props

